using System.ComponentModel;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetches data from an external API endpoint and returns the response body.")]
    public async Task<string> FetchApiData(
        [Description("Relative or absolute URL path to fetch (e.g. /posts/1)")] string path,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching API data from {Path}", path);

        var response = await httpClient.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

[McpServerPromptType]
